   119→// TransitionResult holds the outcome of a state machine transition.
   120→type TransitionResult struct {
   121→	NewPhase Phase
   122→	Actions  []Action
   123→}
   124→
   125→// Transition computes the next phase and required actions given the current
   126→// phase and an event. This is a pure function with no side effects.
   127→//
   128→// Empty or unknown phase values are normalized to PhaseIdle for backward
   129→// compatibility with session state files created before phase tracking.
   130→func Transition(current Phase, event Event, ctx TransitionContext) TransitionResult {
   131→	// Normalize empty/unknown phase to idle for backward compatibility.
   132→	current = PhaseFromString(string(current))
   133→
   134→	switch current {
   135→	case PhaseIdle:
   136→		return transitionFromIdle(event, ctx)
   137→	case PhaseActive:
   138→		return transitionFromActive(event, ctx)
   139→	case PhaseEnded:
   140→		return transitionFromEnded(event, ctx)
   141→	default:
   142→		// PhaseFromString guarantees we only get known phases, but the
   143→		// exhaustive linter requires handling the default case.
   144→		return TransitionResult{NewPhase: PhaseIdle}
   145→	}
   146→}
   147→
   148→func transitionFromIdle(event Event, ctx TransitionContext) TransitionResult {
   149→	switch event {
   150→	case EventTurnStart:
   151→		return TransitionResult{
   152→			NewPhase: PhaseActive,
   153→			Actions:  []Action{ActionUpdateLastInteraction},
   154→		}
   155→	case EventTurnEnd:
   156→		// Turn end while idle is a no-op (no active turn to end).
   157→		return TransitionResult{NewPhase: PhaseIdle}
   158→	case EventGitCommit:
   159→		if ctx.IsRebaseInProgress {
   160→			return TransitionResult{NewPhase: PhaseIdle}
   161→		}
   162→		return TransitionResult{
   163→			NewPhase: PhaseIdle,
   164→			Actions:  []Action{ActionCondense, ActionUpdateLastInteraction},
   165→		}
   166→	case EventSessionStart:
   167→		// Already condensable, no-op.
   168→		return TransitionResult{NewPhase: PhaseIdle}
   169→	case EventSessionStop:
   170→		return TransitionResult{
   171→			NewPhase: PhaseEnded,
   172→			Actions:  []Action{ActionUpdateLastInteraction},
   173→		}
   174→	default:
   175→		return TransitionResult{NewPhase: PhaseIdle}
   176→	}
   177→}
   178→
   179→func transitionFromActive(event Event, ctx TransitionContext) TransitionResult {
   180→	switch event {
   181→	case EventTurnStart:
   182→		// Ctrl-C recovery: agent crashed or user interrupted mid-turn.
   183→		return TransitionResult{
   184→			NewPhase: PhaseActive,
   185→			Actions:  []Action{ActionUpdateLastInteraction},
   186→		}
   187→	case EventTurnEnd:
   188→		return TransitionResult{
   189→			NewPhase: PhaseIdle,
   190→			Actions:  []Action{ActionUpdateLastInteraction},
   191→		}
   192→	case EventGitCommit:
   193→		if ctx.IsRebaseInProgress {
   194→			return TransitionResult{NewPhase: PhaseActive}
   195→		}
   196→		return TransitionResult{
   197→			NewPhase: PhaseActive,
   198→			Actions:  []Action{ActionCondense, ActionUpdateLastInteraction},
   199→		}
   200→	case EventSessionStart:
   201→		return TransitionResult{
   202→			NewPhase: PhaseActive,
   203→			Actions:  []Action{ActionWarnStaleSession},
   204→		}
   205→	case EventSessionStop:
   206→		return TransitionResult{
   207→			NewPhase: PhaseEnded,
   208→			Actions:  []Action{ActionUpdateLastInteraction},
   209→		}
   210→	default:
   211→		return TransitionResult{NewPhase: PhaseActive}
   212→	}
   213→}
   214→
   215→func transitionFromEnded(event Event, ctx TransitionContext) TransitionResult {
   216→	switch event {
   217→	case EventTurnStart:
   218→		return TransitionResult{
   219→			NewPhase: PhaseActive,
   220→			Actions:  []Action{ActionClearEndedAt, ActionUpdateLastInteraction},
   221→		}
   222→	case EventTurnEnd:
   223→		// Turn end while ended is a no-op.
   224→		return TransitionResult{NewPhase: PhaseEnded}
   225→	case EventGitCommit:
   226→		if ctx.IsRebaseInProgress {
   227→			return TransitionResult{NewPhase: PhaseEnded}
   228→		}
   229→		if ctx.HasFilesTouched {
   230→			return TransitionResult{
   231→				NewPhase: PhaseEnded,
   232→				Actions:  []Action{ActionCondenseIfFilesTouched, ActionUpdateLastInteraction},
   233→			}
   234→		}
   235→		return TransitionResult{
   236→			NewPhase: PhaseEnded,
   237→			Actions:  []Action{ActionDiscardIfNoFiles, ActionUpdateLastInteraction},
   238→		}
   239→	case EventSessionStart:
   240→		return TransitionResult{
   241→			NewPhase: PhaseIdle,
   242→			Actions:  []Action{ActionClearEndedAt},
   243→		}
   244→	case EventSessionStop:
   245→		// Already ended, no-op.
   246→		return TransitionResult{NewPhase: PhaseEnded}
   247→	default:
   248→		return TransitionResult{NewPhase: PhaseEnded}
   249→	}
   250→}
