   252→// ActionHandler defines strategy-specific side effects for state transitions.
   253→// The compiler enforces that every strategy-specific action has a handler.
   254→type ActionHandler interface {
   255→	HandleCondense(state *State) error
   256→	HandleCondenseIfFilesTouched(state *State) error
   257→	HandleDiscardIfNoFiles(state *State) error
   258→	HandleWarnStaleSession(state *State) error
   259→}
   260→
   261→// NoOpActionHandler is a default ActionHandler where all methods are no-ops.
   262→// Embed this in handler structs to only override the methods you need.
   263→type NoOpActionHandler struct{}
   264→
   265→func (NoOpActionHandler) HandleCondense(_ *State) error               { return nil }
   266→func (NoOpActionHandler) HandleCondenseIfFilesTouched(_ *State) error { return nil }
   267→func (NoOpActionHandler) HandleDiscardIfNoFiles(_ *State) error       { return nil }
   268→func (NoOpActionHandler) HandleWarnStaleSession(_ *State) error       { return nil }
