   508→// GetNextCheckpointSequence returns the next sequence number for incremental checkpoints.
   509→// It counts existing checkpoint files in the task metadata checkpoints directory.
   510→// Returns 1 if no checkpoints exist yet.
   511→func GetNextCheckpointSequence(sessionID, taskToolUseID string) int {
   512→	// Use the session ID directly as the metadata directory name
   513→	sessionMetadataDir := paths.SessionMetadataDirFromSessionID(sessionID)
   514→	taskMetadataDir := strategy.TaskMetadataDir(sessionMetadataDir, taskToolUseID)
   515→	checkpointsDir := filepath.Join(taskMetadataDir, "checkpoints")
   516→
   517→	entries, err := os.ReadDir(checkpointsDir)
   518→	if err != nil {
   519→		// Directory doesn't exist or can't be read - start at 1
   520→		return 1
   521→	}
   522→
   523→	// Count JSON files (checkpoints)
   524→	count := 0
   525→	for _, entry := range entries {
   526→		if !entry.IsDir() && strings.HasSuffix(entry.Name(), ".json") {
   527→			count++
   528→		}
   529→	}
   530→
   531→	return count + 1
   532→}
