   211→	data, err := os.ReadFile(input.SessionRef)
   212→	if err != nil {
   213→		return nil, fmt.Errorf("failed to read transcript: %w", err)
   214→	}
   215→
   216→	// Parse to extract computed fields
   217→	modifiedFiles, err := ExtractModifiedFiles(data)
   218→	if err != nil {
   219→		// Non-fatal: we can still return the session without modified files
   220→		modifiedFiles = nil
   221→	}
   222→
   223→	return &agent.AgentSession{
   224→		SessionID:     input.SessionID,
   225→		AgentName:     g.Name(),
   226→		SessionRef:    input.SessionRef,
   227→		StartTime:     time.Now(),
   228→		NativeData:    data,
   229→		ModifiedFiles: modifiedFiles,
   230→	}, nil
   231→}
   232→
   233→// WriteSession writes a session to Gemini's storage (JSON transcript file).
   234→// Uses the NativeData field which contains raw JSON bytes.
   235→func (g *GeminiCLIAgent) WriteSession(session *agent.AgentSession) error {
   236→	if session == nil {
   237→		return errors.New("session is nil")
   238→	}
   239→
   240→	// Verify this session belongs to Gemini CLI
   241→	if session.AgentName != "" && session.AgentName != g.Name() {
   242→		return fmt.Errorf("session belongs to agent %q, not %q", session.AgentName, g.Name())
   243→	}
   244→
   245→	if session.SessionRef == "" {
   246→		return errors.New("session reference (transcript path) is required")
   247→	}
   248→
   249→	if len(session.NativeData) == 0 {
   250→		return errors.New("session has no native data to write")
   251→	}
   252→
   253→	// Write the raw JSON data
   254→	if err := os.WriteFile(session.SessionRef, session.NativeData, 0o600); err != nil {
   255→		return fmt.Errorf("failed to write transcript: %w", err)
   256→	}
   257→
   258→	return nil
   259→}
   260→
   261→// FormatResumeCommand returns the command to resume a Gemini CLI session.
   262→func (g *GeminiCLIAgent) FormatResumeCommand(sessionID string) string {
   263→	return "gemini --resume " + sessionID
   264→}
   265→
   266→// SanitizePathForGemini converts a path to Gemini's project directory format.
   267→// Gemini uses a hash-like sanitization similar to Claude.
   268→var nonAlphanumericRegex = regexp.MustCompile(`[^a-zA-Z0-9]`)
   269→
   270→func SanitizePathForGemini(path string) string {
   271→	return nonAlphanumericRegex.ReplaceAllString(path, "-")
   272→}
   273→
   274→// TranscriptAnalyzer interface implementation
   275→
   276→// GetTranscriptPosition returns the current message count of a Gemini transcript.
   277→// Gemini uses JSON format with a messages array, so position is the message count.
   278→// Returns 0 if the file doesn't exist or is empty.
   279→func (g *GeminiCLIAgent) GetTranscriptPosition(path string) (int, error) {
   280→	if path == "" {
   281→		return 0, nil
   282→	}
   283→
   284→	data, err := os.ReadFile(path) //nolint:gosec // Reading from controlled transcript path
   285→	if err != nil {
   286→		if os.IsNotExist(err) {
   287→			return 0, nil
   288→		}
   289→		return 0, fmt.Errorf("failed to read transcript: %w", err)
   290→	}
   291→
   292→	if len(data) == 0 {
   293→		return 0, nil
   294→	}
   295→
   296→	transcript, err := ParseTranscript(data)
   297→	if err != nil {
   298→		return 0, fmt.Errorf("failed to parse transcript: %w", err)
   299→	}
   300→
   301→	return len(transcript.Messages), nil
   302→}
   303→
   304→// ExtractModifiedFilesFromOffset extracts files modified since a given message index.
   305→// For Gemini (JSON format), offset is the starting message index.
   306→// Returns:
   307→//   - files: list of file paths modified by Gemini (from Write/Edit tools)
   308→//   - currentPosition: total number of messages in the transcript
   309→//   - error: any error encountered during reading
   310→func (g *GeminiCLIAgent) ExtractModifiedFilesFromOffset(path string, startOffset int) (files []string, currentPosition int, err error) {
   311→	if path == "" {
   312→		return nil, 0, nil
   313→	}
   314→
   315→	data, readErr := os.ReadFile(path) //nolint:gosec // Reading from controlled transcript path
   316→	if readErr != nil {
   317→		if os.IsNotExist(readErr) {
   318→			return nil, 0, nil
   319→		}
   320→		return nil, 0, fmt.Errorf("failed to read transcript: %w", readErr)
   321→	}
   322→
   323→	if len(data) == 0 {
   324→		return nil, 0, nil
   325→	}
   326→
   327→	transcript, parseErr := ParseTranscript(data)
   328→	if parseErr != nil {
   329→		return nil, 0, parseErr
   330→	}
   331→
   332→	totalMessages := len(transcript.Messages)
   333→
   334→	// Extract files from messages starting at startOffset
   335→	fileSet := make(map[string]bool)
   336→	for i := startOffset; i < len(transcript.Messages); i++ {
   337→		msg := transcript.Messages[i]
   338→		// Only process gemini messages (assistant messages)
   339→		if msg.Type != MessageTypeGemini {
   340→			continue
   341→		}
   342→
   343→		// Process tool calls in this message
   344→		for _, toolCall := range msg.ToolCalls {
   345→			// Check if it's a file modification tool
   346→			isModifyTool := false
   347→			for _, name := range FileModificationTools {
   348→				if toolCall.Name == name {
   349→					isModifyTool = true
   350→					break
   351→				}
   352→			}
   353→
   354→			if !isModifyTool {
   355→				continue
   356→			}
   357→
   358→			// Extract file path from args map
   359→			var file string
   360→			if fp, ok := toolCall.Args["file_path"].(string); ok && fp != "" {
   361→				file = fp
   362→			} else if p, ok := toolCall.Args["path"].(string); ok && p != "" {
   363→				file = p
   364→			} else if fn, ok := toolCall.Args["filename"].(string); ok && fn != "" {
   365→				file = fn
   366→			}
   367→
   368→			if file != "" && !fileSet[file] {
   369→				fileSet[file] = true
   370→				files = append(files, file)
   371→			}
   372→		}
   373→	}
   374→
   375→	return files, totalMessages, nil
   376→}
   377→
   378→// TranscriptChunker interface implementation
   379→
   380→// ChunkTranscript splits a Gemini JSON transcript by distributing messages across chunks.
   381→// Gemini uses JSON format with a {"messages": [...]} structure, so chunking splits
   382→// the messages array while preserving the JSON structure in each chunk.
   383→func (g *GeminiCLIAgent) ChunkTranscript(content []byte, maxSize int) ([][]byte, error) {
   384→	var transcript GeminiTranscript
   385→	if err := json.Unmarshal(content, &transcript); err != nil {
   386→		// Fall back to JSONL chunking if not valid Gemini JSON
   387→		chunks, chunkErr := agent.ChunkJSONL(content, maxSize)
   388→		if chunkErr != nil {
   389→			return nil, fmt.Errorf("failed to chunk as JSONL: %w", chunkErr)
   390→		}
   391→		return chunks, nil
   392→	}
   393→
   394→	if len(transcript.Messages) == 0 {
   395→		return [][]byte{content}, nil
   396→	}
   397→
   398→	var chunks [][]byte
   399→	var currentMessages []GeminiMessage
   400→	currentSize := len(`{"messages":[]}`) // Base JSON structure size
   401→
   402→	for i, msg := range transcript.Messages {
   403→		// Marshal message to get its size
   404→		msgBytes, err := json.Marshal(msg)
   405→		if err != nil {
   406→			logging.Warn(context.Background(), "failed to marshal Gemini message during chunking",
   407→				slog.Int("message_index", i),
   408→				slog.String("error", err.Error()),
   409→			)
   410→			continue
   411→		}
   412→		msgSize := len(msgBytes) + 1 // +1 for comma separator
   413→
   414→		if currentSize+msgSize > maxSize && len(currentMessages) > 0 {
   415→			// Save current chunk
   416→			chunkData, err := json.Marshal(GeminiTranscript{Messages: currentMessages})
   417→			if err != nil {
   418→				return nil, fmt.Errorf("failed to marshal chunk: %w", err)
   419→			}
   420→			chunks = append(chunks, chunkData)
   421→
   422→			// Start new chunk
   423→			currentMessages = nil
   424→			currentSize = len(`{"messages":[]}`)
   425→		}
   426→
   427→		currentMessages = append(currentMessages, msg)
   428→		currentSize += msgSize
   429→	}
   430→
   431→	// Add the last chunk
   432→	if len(currentMessages) > 0 {
   433→		chunkData, err := json.Marshal(GeminiTranscript{Messages: currentMessages})
   434→		if err != nil {
   435→			return nil, fmt.Errorf("failed to marshal final chunk: %w", err)
   436→		}
   437→		chunks = append(chunks, chunkData)
   438→	}
   439→
   440→	// Ensure we created at least one chunk (could be empty if all messages failed to marshal)
   441→	if len(chunks) == 0 {
   442→		return nil, errors.New("failed to create any chunks: all messages failed to marshal")
   443→	}
   444→
   445→	return chunks, nil
   446→}
   447→
   448→// ReassembleTranscript merges Gemini JSON chunks by combining their message arrays.
   449→func (g *GeminiCLIAgent) ReassembleTranscript(chunks [][]byte) ([]byte, error) {
   450→	var allMessages []GeminiMessage
   451→
   452→	for _, chunk := range chunks {
   453→		var transcript GeminiTranscript
   454→		if err := json.Unmarshal(chunk, &transcript); err != nil {
   455→			return nil, fmt.Errorf("failed to unmarshal chunk: %w", err)
   456→		}
   457→		allMessages = append(allMessages, transcript.Messages...)
   458→	}
   459→
   460→	result, err := json.Marshal(GeminiTranscript{Messages: allMessages})
   461→	if err != nil {
   462→		return nil, fmt.Errorf("failed to marshal reassembled transcript: %w", err)
   463→	}
   464→	return result, nil
   465→}
   466→

