	switch e {
	case SessionStart:
		return "SessionStart"
	case TurnStart:
		return "TurnStart"
	case TurnEnd:
		return "TurnEnd"
	case Compaction:
		return "Compaction"
	case SessionEnd:
		return "SessionEnd"
	case SubagentStart:
		return "SubagentStart"
	case SubagentEnd:
		return "SubagentEnd"
	default:
		return "Unknown"
	}
}

