   447→// preTaskStateFile returns the absolute path to the pre-task state file for a tool use.
   448→// Works correctly from any subdirectory within the repository.
   449→func preTaskStateFile(toolUseID string) string {
   450→	tmpDirAbs, err := paths.AbsPath(paths.EntireTmpDir)
   451→	if err != nil {
