   157→				} `json:"messages"`
   158→			}
   159→			if jsonErr := json.Unmarshal(data, &transcript); jsonErr == nil {
   160→				startMessageIndex = len(transcript.Messages)
   161→				if startMessageIndex > 0 {
   162→					lastMessageID = transcript.Messages[startMessageIndex-1].ID
   163→				}
