   226→// FileChanges holds categorized file changes from git status.
   227→type FileChanges struct {
   228→	Modified []string // Modified or staged files
   229→	New      []string // Untracked files (filtered if previouslyUntracked provided)
   230→	Deleted  []string // Deleted files (staged or unstaged)
   231→}
   232→
   233→// DetectFileChanges returns categorized file changes from the current git status.
   234→//
   235→// previouslyUntracked controls new-file detection:
   236→//   - nil: all untracked files go into New
   237→//   - non-nil: only untracked files NOT in the pre-existing set go into New
   238→//
   239→// Modified includes both worktree and staging modified/added files.
   240→// Deleted includes both staged and unstaged deletions.
   241→// All results exclude .entire/ directory.
   242→func DetectFileChanges(previouslyUntracked []string) (*FileChanges, error) {
   243→	repo, err := openRepository()
   244→	if err != nil {
   245→		return nil, fmt.Errorf("failed to open repository: %w", err)
   246→	}
   247→
   248→	worktree, err := repo.Worktree()
   249→	if err != nil {
   250→		return nil, fmt.Errorf("failed to get worktree: %w", err)
   251→	}
   252→
   253→	status, err := worktree.Status()
   254→	if err != nil {
   255→		return nil, fmt.Errorf("failed to get status: %w", err)
   256→	}
   257→
   258→	// Build set of pre-existing untracked files for quick lookup
   259→	var preExisting map[string]bool
   260→	if previouslyUntracked != nil {
   261→		preExisting = make(map[string]bool, len(previouslyUntracked))
   262→		for _, f := range previouslyUntracked {
   263→			preExisting[f] = true
   264→		}
   265→	}
   266→
   267→	var changes FileChanges
   268→	for file, st := range status {
   269→		if paths.IsInfrastructurePath(file) {
   270→			continue
   271→		}
   272→
   273→		switch {
   274→		case st.Worktree == git.Untracked:
   275→			if preExisting != nil {
   276→				if !preExisting[file] {
   277→					changes.New = append(changes.New, file)
   278→				}
   279→			} else {
   280→				changes.New = append(changes.New, file)
   281→			}
   282→		case st.Worktree == git.Deleted || st.Staging == git.Deleted:
   283→			changes.Deleted = append(changes.Deleted, file)
   284→		case st.Worktree == git.Modified || st.Staging == git.Modified ||
   285→			st.Worktree == git.Added || st.Staging == git.Added:
   286→			changes.Modified = append(changes.Modified, file)
   287→		}
   288→	}
   289→
   290→	return &changes, nil
   291→}
