   375→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "hooks"), ag.Name())
   376→	logging.Debug(logCtx, "gemini-after-tool",
   377→		slog.String("hook", "after-tool"),
   378→		slog.String("hook_type", "tool"),
   379→		slog.String("model_session_id", input.SessionID),
   380→		slog.String("tool_name", input.ToolName),
   381→	)
   382→
   383→	// For now, AfterTool is mainly for logging
   384→	// Future: Could be used for incremental checkpoints similar to Claude's PostTodo
   385→	return nil
   386→}
